        data: {"result": {"minY": 1.0, "minX": 0.0, "maxY": 2397.0, "series": [{"data": [[300.0, 281.0], [200.0, 912.0], [400.0, 2.0], [500.0, 5.0]], "isOverall": false, "label": "登录", "isController": true}, {"data": [[300.0, 281.0], [200.0, 912.0], [400.0, 2.0], [500.0, 5.0]], "isOverall": false, "label": "登录接口", "isController": false}, {"data": [[0.0, 2397.0], [300.0, 1.0], [100.0, 1.0], [200.0, 1.0]], "isOverall": false, "label": "查询用户接口", "isController": false}, {"data": [[0.0, 2397.0], [300.0, 1.0], [100.0, 1.0], [200.0, 1.0]], "isOverall": false, "label": "查询1次", "isController": true}], "supportsControllersDiscrimination": true, "granularity": 100, "maxX": 500.0, "title": "Response Time Distribution"}},
